import React from 'react';
import Header from './Header';
import AddContact from './AddContact';
import ContactList from './ContactList';

function App() {

  const contacts = [
    {
      id: "1",
      name: "Aditya Mahamuni",
      email: "adimahamuni25@gmail.com",
    },
    {
      id: "2",
      name: "Adity",
      email: "adimahamuni25@gmail.com",
    },
  ]
  return (
    <div className="ui container">
      <Header />
      <AddContact />
      <ContactList />
    </div>
  );
}

export default App;
